QSS_TEMPLATE = '/* RimeConfig 0.2.0 · 单模板（@ACCENT@ 等令牌占位符，由 theme.py 注入三套皮肤）\n   选择器严格沿用真实代码（不改控件对象名）；色值/字体 token 化，\n   取值见 design/themes/TOKENS.md §1.1 权威值（A/B/C）。\n   固定字号 / 间距 / 圆角保留字面量（零抖动）。\n\n   dark 独有选择器已并入本模板：QMenu::separator / QTableView（含 ::item:selected）\n   / QComboBox::drop-down / QSpinBox::up-button,down-button，均用同样占位符映射。\n*/\n\n* {\n    font-family: @FONT_UI@;\n    font-size: 13px;\n    color: @TEXT_PRIMARY@;\n}\n\nQWidget {\n    background-color: transparent;\n}\n\n/* Pure layout containers stay transparent; interactive surfaces are declared below. */\nQStackedWidget, QScrollArea {\n    background-color: transparent;\n    border: none;\n}\n\nQScrollArea > QWidget > QWidget,\nQDialog QLabel {\n    background-color: transparent;\n}\n\n/* ---------- 主窗口 / 容器卡片 ---------- */\nQMainWindow, QWidget#Central, QTabWidget::pane {\n    background-color: @BG_APP@;\n}\n\nCard, QGroupBox {\n    background-color: @BG_SURFACE@;\n    border: 1px solid @BORDER@;\n    border-radius: 10px;\n}\n\nQGroupBox {\n    margin-top: 10px;\n    padding: 10px;\n    font-weight: bold;\n}\n\nQGroupBox::title {\n    subcontrol-origin: margin;\n    left: 12px;\n    padding: 0 4px;\n    color: @ACCENT@;\n}\n\n/* ---------- 侧栏导航 ---------- */\nQListWidget#Sidebar {\n    background-color: @BG_SIDEBAR@;\n    border: none;\n    border-right: 1px solid @BORDER@;\n    padding: 8px;\n    outline: 0;\n}\n\nQListWidget#Sidebar::item {\n    height: 38px;\n    padding-left: 14px;\n    border-radius: 8px;\n    color: @TEXT_PRIMARY@;\n}\n\nQListWidget#Sidebar::item:hover {\n    background-color: @BG_HOVER@;\n}\n\nQListWidget#Sidebar::item:selected {\n    background-color: @SELECTION_BG@;\n    color: @SELECTION_TEXT@;\n    font-weight: bold;\n}\n\n/* ---------- 按钮 ---------- */\nQPushButton {\n    background-color: @BG_SURFACE@;\n    border: 1px solid @BORDER@;\n    border-radius: 8px;\n    padding: 6px 14px;\n    color: @TEXT_PRIMARY@;\n}\n\nQPushButton:hover {\n    border-color: @ACCENT_HOVER@;\n    color: @ACCENT@;\n}\n\nQPushButton:pressed {\n    background-color: @BG_ACTIVE_NAV@;\n}\n\nQPushButton:disabled {\n    color: @TEXT_MUTED@;\n    background-color: @BG_APP@;\n    border-color: @BORDER@;\n}\n\nQPushButton#Primary {\n    background-color: @ACCENT@;\n    border: none;\n    color: @ON_ACCENT@;\n    font-weight: bold;\n}\n\nQPushButton#Primary:hover {\n    background-color: @ACCENT_HOVER@;\n    color: @ON_ACCENT@;\n}\n\nQPushButton#Primary:disabled {\n    background-color: @BORDER_STRONG@;\n    border: 1px solid @BORDER_STRONG@;\n    color: @TEXT_MUTED@;\n}\n\nQPushButton#Danger {\n    border-color: @BORDER@;\n    color: @CONFLICT_TEXT@;\n}\n\nQPushButton#Danger:hover {\n    border-color: @CONFLICT_TEXT@;\n    color: @CONFLICT_TEXT@;\n}\n\n/* ---------- 输入框 ---------- */\nQLineEdit, QSpinBox, QComboBox, QTextEdit {\n    background-color: @BG_SURFACE@;\n    border: 1px solid @BORDER@;\n    border-radius: 8px;\n    padding: 5px 8px;\n}\n\nQLineEdit:focus, QSpinBox:focus, QComboBox:focus, QTextEdit:focus {\n    border: 1px solid @ACCENT_HOVER@;\n}\n\nQComboBox QAbstractItemView {\n    background-color: @BG_SURFACE@;\n    border: 1px solid @BORDER@;\n    selection-background-color: @SELECTION_BG@;\n    selection-color: @SELECTION_TEXT@;\n}\n\n/* dark 独有选择器：下拉箭头（无边框） */\nQComboBox::drop-down {\n    border: none;\n}\n\n/* dark 独有选择器：微调按钮底色 */\nQSpinBox::up-button, QSpinBox::down-button {\n    background-color: @BG_ELEVATED@;\n}\n\n/* ---------- 表格 ---------- */\nQTableWidget {\n    background-color: @BG_SURFACE@;\n    border: 1px solid @BORDER@;\n    border-radius: 8px;\n    gridline-color: @TABLE_GRID@;\n    selection-background-color: @SELECTION_BG@;\n    selection-color: @SELECTION_TEXT@;\n}\n\nQTableWidget::viewport, QTableView::viewport, QListWidget::viewport {\n    background-color: @BG_SURFACE@;\n}\n\nQTableWidget::item, QTableView::item {\n    background-color: @BG_SURFACE@;\n}\n\nQHeaderView::section {\n    background-color: @BG_APP@;\n    border: none;\n    border-bottom: 1px solid @BORDER@;\n    padding: 6px;\n    color: @TEXT_SECONDARY@;\n    font-weight: bold;\n}\n\nQTableWidget::item:selected {\n    background-color: @SELECTION_BG@;\n    color: @SELECTION_TEXT@;\n}\n\n/* 冲突高亮行 */\nQTableWidget::item[conflict="true"] {\n    background-color: @CONFLICT_BG@;\n    color: @CONFLICT_TEXT@;\n}\n\n/* dark 独有选择器：QTableView（与 QTableWidget 视觉一致） */\nQTableView {\n    background-color: @BG_SURFACE@;\n    border: 1px solid @BORDER@;\n    gridline-color: @TABLE_GRID@;\n    selection-background-color: @SELECTION_BG@;\n    selection-color: @SELECTION_TEXT@;\n    color: @TEXT_PRIMARY@;\n}\n\nQTableView::item:selected {\n    background-color: @SELECTION_BG@;\n    color: @SELECTION_TEXT@;\n}\n\n/* ---------- 复选框 / 开关 ---------- */\nQCheckBox {\n    spacing: 6px;\n}\n\nQCheckBox::indicator {\n    width: 16px;\n    height: 16px;\n}\n\nQCheckBox::indicator:unchecked {\n    background-color: @BG_SURFACE@;\n    border: 1px solid @BORDER_STRONG@;\n    border-radius: 4px;\n}\n\nQCheckBox::indicator:checked {\n    background-color: @ACCENT@;\n    border: 1px solid @ACCENT@;\n    border-radius: 4px;\n    image: url(check.svg);\n}\n\nQCheckBox::indicator:indeterminate {\n    background-color: @BG_SURFACE@;\n    border: 1px solid @ACCENT@;\n    border-radius: 4px;\n    image: url(check.svg);\n}\n\nQCheckBox::indicator:disabled:unchecked {\n    background-color: @BG_APP@;\n    border: 1px solid @BORDER@;\n    border-radius: 4px;\n}\n\nQCheckBox::indicator:disabled:checked {\n    background-color: @BORDER_STRONG@;\n    border: 1px solid @BORDER_STRONG@;\n    border-radius: 4px;\n    image: url(check-disabled.svg);\n}\n\n/* 表格内 item 复选框（最左『选择』列）：原生小方块 → 真对勾 */\nQTableView::indicator {\n    width: 16px;\n    height: 16px;\n}\n\nQTableView::indicator:unchecked {\n    background-color: @BG_SURFACE@;\n    border: 1px solid @BORDER_STRONG@;\n    border-radius: 4px;\n}\n\nQTableView::indicator:checked {\n    background-color: @ACCENT@;\n    border: 1px solid @ACCENT@;\n    border-radius: 4px;\n    image: url(check.svg);\n}\n\nQTableView::indicator:disabled:unchecked {\n    background-color: @BG_APP@;\n    border: 1px solid @BORDER@;\n    border-radius: 4px;\n}\n\nQTableView::indicator:disabled:checked {\n    background-color: @BORDER_STRONG@;\n    border: 1px solid @BORDER_STRONG@;\n    border-radius: 4px;\n    image: url(check-disabled.svg);\n}\n\n/* ---------- 选项卡（若使用 QTabWidget） ---------- */\nQTabWidget::pane {\n    border: 1px solid @BORDER@;\n    border-radius: 10px;\n    top: -1px;\n}\n\nQTabBar::tab {\n    background-color: @BG_APP@;\n    border: 1px solid @BORDER@;\n    border-bottom: none;\n    border-top-left-radius: 8px;\n    border-top-right-radius: 8px;\n    padding: 6px 16px;\n}\n\nQTabBar::tab:selected {\n    background-color: @BG_SURFACE@;\n    color: @ACCENT@;\n    font-weight: bold;\n    border-top: 3px solid @ACCENT@;\n}\n\nQTabBar::tab:!selected {\n    color: @TEXT_SECONDARY@;\n}\n\nQTabBar::tab:hover {\n    color: @ACCENT@;\n}\n\n/* ---------- 菜单 ---------- */\nQMenu {\n    background-color: @BG_SURFACE@;\n    border: 1px solid @BORDER@;\n    border-radius: 8px;\n    padding: 4px;\n}\n\nQMenu::item {\n    padding: 6px 18px;\n    border-radius: 6px;\n}\n\nQMenu::item:selected {\n    background-color: @SELECTION_BG@;\n    color: @SELECTION_TEXT@;\n}\n\n/* dark 独有选择器：菜单分隔线 */\nQMenu::separator {\n    height: 1px;\n    background: @BORDER_STRONG@;\n    margin: 4px 8px;\n}\n\n/* ---------- 状态栏 / 滚动条 ---------- */\nQStatusBar {\n    background-color: @BG_SURFACE@;\n    border-top: 1px solid @BORDER@;\n    color: @TEXT_MUTED@;\n}\n\nQScrollBar:vertical {\n    background: @BG_ELEVATED@;\n    border: 1px solid @BORDER@;\n    border-radius: 6px;\n    width: 12px;\n    margin: 2px;\n}\n\nQScrollBar::handle:vertical {\n    background: @TEXT_MUTED@;\n    border: 2px solid @BG_ELEVATED@;\n    border-radius: 5px;\n    min-height: 32px;\n}\n\nQScrollBar::handle:vertical:hover, QScrollBar::handle:vertical:pressed {\n    background: @ACCENT@;\n}\n\nQScrollBar::add-page:vertical, QScrollBar::sub-page:vertical {\n    background: transparent;\n}\n\nQScrollBar::add-line:vertical, QScrollBar::sub-line:vertical {\n    height: 0;\n}\n\n/* ---------- 区块标题（替代禁用主按钮模拟标题） ---------- */\nQLabel#BlockTitle {\n    font-family: @FONT_HEADING@;\n    font-size: 14px;\n    font-weight: bold;\n    color: @TEXT_PRIMARY@;\n    padding: 2px 2px 6px 2px;\n}\n\n/* ---------- 语义化标签（错误 / 信息 / 静音信息） ---------- */\n*[role="success"] {\n    color: @SUCCESS_TEXT@;\n}\n\n*[role="info"] {\n    color: @INFO_TEXT@;\n}\n\n*[role="warning"] {\n    color: @WARNING_TEXT@;\n}\n\n*[role="error"] {\n    color: @ERROR_TEXT@;\n}\n\n*[role="duplicate"] {\n    color: @DUPLICATE_TEXT@;\n}\n\n*[role="neutral"] {\n    color: @NEUTRAL_TEXT@;\n}\n\nQLabel#MutedVersion {\n    color: @TEXT_MUTED@;\n    font-size: 12px;\n}\n\n\n/* ---------- 设置页主题卡片 ---------- */\nQWidget#ThemeSelector {\n    background: transparent;\n}\n\nQFrame#ThemeCard {\n    background-color: @BG_ELEVATED@;\n    border: 1px solid @BORDER@;\n    border-radius: 8px;\n}\n\nQFrame#ThemeCard:hover {\n    border-color: @ACCENT_HOVER@;\n}\n\nQFrame#ThemeCard[selected="true"] {\n    background-color: @ACCENT_SOFT@;\n    border: 2px solid @ACCENT@;\n}\n\nQLabel#ThemeCardTitle {\n    color: @TEXT_PRIMARY@;\n    font-weight: bold;\n}\n\nQLabel#ThemeCardDesc {\n    color: @TEXT_SECONDARY@;\n    font-size: 12px;\n}\n\nQLabel#ThemeCardCheck {\n    background-color: @ACCENT@;\n    border-radius: 10px;\n    color: @ON_ACCENT@;\n    font-size: 12px;\n    font-weight: bold;\n}\n\n\n/* ---------- 编码建议列表 ---------- */\nQFrame#EncodingSuggestion {\n    background-color: @BG_ELEVATED@;\n    border: 1px solid @BORDER@;\n    border-radius: 6px;\n}\n\nQFrame#EncodingSuggestion:hover, QFrame#EncodingSuggestion[selected="true"] {\n    border-color: @ACCENT@;\n    background-color: @ACCENT_SOFT@;\n}\n\nQLabel#SuggestionName {\n    color: @TEXT_SECONDARY@;\n    font-weight: bold;\n    min-width: 72px;\n}\n\nQLabel#SuggestionCode {\n    color: @ACCENT@;\n    font-family: @FONT_MONO@;\n}\n\nQLabel#SuggestionState {\n    font-weight: bold;\n    min-width: 58px;\n}\n\n\nQPushButton#SuggestionAdd {\n    min-width: 52px;\n    min-height: 26px;\n    padding: 3px 8px;\n    border-radius: 5px;\n    color: @ACCENT@;\n}\n\nQFrame#ResultToast {\n    background-color: @BG_ELEVATED@;\n    border: 1px solid @BORDER_STRONG@;\n    border-left: 4px solid @ACCENT@;\n    border-radius: 6px;\n}\n\nQFrame#ResultToast[role="success"] { border-left-color: @SUCCESS_TEXT@; }\nQFrame#ResultToast[role="error"] { border-left-color: @ERROR_TEXT@; }\nQLabel#ResultToastTitle { font-weight: bold; color: @TEXT_PRIMARY@; }\nQLabel#ResultToastMessage { color: @TEXT_SECONDARY@; }\n\n\nQLabel#ExtraCodeName {\n    min-width: 46px;\n    color: @TEXT_SECONDARY@;\n    font-weight: bold;\n}\n\nQPushButton#ToastClose {\n    border: none;\n    background: transparent;\n    color: @TEXT_MUTED@;\n    font-size: 18px;\n    padding: 0;\n}\n\nQPushButton#ToastClose:hover { color: @TEXT_PRIMARY@; }\n\n\nQLabel#DeleteCode { font-family: @FONT_MONO@; color: @TEXT_PRIMARY@; }\nQLabel#DeleteWeight { min-width: 42px; color: @TEXT_SECONDARY@; }\nQLabel#ToastPhrase { color: @TEXT_PRIMARY@; font-weight: bold; }\nQLabel#ToastCodes { color: @ACCENT@; font-family: @FONT_MONO@; }\n\n/* ---------- Rime 实时候选预览 ---------- */\nQWidget#RimePreviewPanel {\n    background: @ACCENT_SOFT@;\n    border-top: 1px solid @BORDER_STRONG@;\n    border-bottom: 1px solid @BORDER_STRONG@;\n    border-radius: 4px;\n}\nQLabel#RimePreviewStatus, QLabel#RimePreviewCandidate {\n    color: @TEXT_PRIMARY@;\n    font-size: 15px;\n    font-weight: 600;\n}\nQLabel#RimePreviewWeight, QLabel#RimePreviewWeightTitle {\n    color: @ACCENT@;\n    font-family: @FONT_MONO@;\n    font-size: 13px;\n    font-weight: bold;\n}\nQLabel#RimePreviewDetails {\n    color: @NEUTRAL_TEXT@;\n    font-size: 12px;\n}\n\n/* Compact visual boundary between the top tabs and the phrase action strip. */\nQTabWidget#TopTabs::pane {\n    border: 1px solid @BORDER_STRONG@;\n    border-top: 0;\n    border-radius: 0 0 8px 8px;\n}\nQTabWidget#TopTabs QTabBar::tab {\n    min-height: 25px;\n}\nQWidget#PhraseToolbar {\n    background: @BG_SURFACE@;\n    border: 1px solid @BORDER@;\n    border-radius: 6px;\n}\nQWidget#PhraseToolbar QPushButton,\nQWidget#PhraseToolbar QComboBox {\n    min-height: 26px;\n}\n\n\nQWidget#LibrarySideControls {\n    background: @BG_SURFACE@;\n    border: 1px solid @BORDER@;\n    border-radius: 6px;\n    padding: 4px;\n}\n\n/* ---------- 统一弹窗工作台 ---------- */\nQDialog {\n    background-color: @BG_APP@;\n}\nQDialog QWidget#DialogSection, QFrame#DialogSection {\n    background-color: @BG_SURFACE@;\n    border: 1px solid @BORDER@;\n    border-radius: 8px;\n}\nQLabel#DialogSectionTitle {\n    color: @ACCENT@;\n    font-size: 14px;\n    font-weight: bold;\n    padding: 0 2px 5px 2px;\n}\nQDialogButtonBox QPushButton {\n    min-width: 88px;\n}\n\n/* ---------- 多编码编辑专用工作台 ---------- */\nQFrame#MultiCodeSection {\n    background-color: @BG_SURFACE@;\n    border: 1px solid @BORDER@;\n    border-radius: 8px;\n}\nQLabel#MultiCodeSectionTitle {\n    background: transparent;\n    border: none;\n    color: @ACCENT@;\n    font-size: 14px;\n    font-weight: bold;\n    padding: 0 0 5px 0;\n}\nQWidget#ExistingCodeHeader {\n    background-color: @BG_ELEVATED@;\n    border: none;\n    border-bottom: 1px solid @BORDER@;\n}\nQFrame#ExistingCodeRow {\n    background-color: @BG_SURFACE@;\n    border: 1px solid @BORDER@;\n    border-radius: 6px;\n}\nQWidget#RimePreviewPanel {\n    background-color: @ACCENT_SOFT@;\n    border: 1px solid @ACCENT@;\n    border-radius: 8px;\n}\nQFrame#EncodingSuggestion QLabel#SuggestionName {\n    background-color: @ACCENT_SOFT@;\n    border: 1px solid @BORDER@;\n    border-radius: 4px;\n    padding: 3px 6px;\n}\n\nQDialog, QDialog * {\n    font-family: @FONT_UI@;\n    font-size: 14px;\n}\nQDialog QLineEdit, QDialog QComboBox, QDialog QSpinBox {\n    min-height: 26px;\n}\nQPushButton#SecondaryAction {\n    color: @ACCENT@;\n    border-color: @ACCENT@;\n}\nQPushButton#SecondaryAction:hover {\n    background-color: @ACCENT_SOFT@;\n    color: @ACCENT_HOVER@;\n}\n\nQPlainTextEdit {\n    background-color: @BG_SURFACE@;\n    border: 1px solid @BORDER@;\n    border-radius: 8px;\n    padding: 8px;\n}\nQWidget#DialogSection, QFrame#DialogSection {\n    background-color: @BG_SURFACE@;\n}\nQDialog QTableWidget, QDialog QTableView, QDialog QPlainTextEdit {\n    background-color: @BG_SURFACE@;\n}\nQDialog QHeaderView::section {\n    background-color: @BG_ELEVATED@;\n    border-bottom: 1px solid @BORDER@;\n}\n'
